ursor: pointer; }\n  .stack { display: flex; flex-direction: column; gap: 10px; }\n  .recent-table { font-family: var(--font-ui); font-size: .85rem; width: 100%; border-collapse: collapse; }\n  .recent-table th { text-align: left; padding: 10px 14px; color: var(--rr-slate-dark); font-size: .68rem; letter-spacing: .08em; text-transform: uppercase; border-bottom: 1px solid var(--rr-parchment); font-weight: 600; }\n  .recent-table td { padding: 12px 14px; border-bottom: 1px solid var(--rr-parchment); }\n  .recent-table tr:last-child td { border-bottom: none; }\n  .recent-table .id { font-family: var(--font-mono); font-size: .76rem; color: var(--rr-slate-dark); }\n\n  /* Drawer */\n  .drawer-overlay { position: fixed; inset: 0; background: rgba(10,25,47,0.4); z-index: 40; }\n  .drawer { position: fixed; top: 0; bottom: 0; right: 0; width: min(560px,100%); background: #fff; box-shadow: var(--shadow-xl); display: flex; flex-direction: column; z-index: 50; animation: slideIn 350ms cubic-bezier(0.16,1,0.3,1); }\n  @keyframes slideIn { from { transform: translateX(100%); } to { transform: translateX(0); } }\n  .drawer-header { padding: 22px 28px; border-bottom: 1px solid var(--rr-parchment); display: flex; justify-content: space-between; align-items: flex-start; gap: 16px; }\n  .drawer-meta { font-size: .68rem; font-weight: 600; letter-spacing: .12em; text-transform: uppercase; color: hsl(var(--primary)); }\n  .drawer-title { font-family: var(--font-display); font-weight: 700; font-size: 1.4rem; color: var(--rr-navy-800); letter-spacing: -.02em; margin: 4px 0 6px; }\n  .drawer-sub { font-size: .82rem; color: var(--rr-slate-dark); }\n  .drawer-body { flex: 1; padding: 22px 28px; overflow-y: auto; display: flex; flex-direction: column; gap: 18px; }\n  .drawer-footer { padding: 16px 28px; border-top: 1px solid var(--rr-parchment); display: flex; gap: 10px; justify-content: flex-end; background: var(--rr-off-white); }\n  .drawer-x { background: none; border: none; cursor: pointer; padding: 6px; color: var(--rr-slate-dark); border-radius: 4px; }\n  .drawer-x:hover { background: var(--rr-off-white); color: var(--rr-ink); }\n\n  /* Form fields */\n  .field { display: flex; flex-direction: column; gap: 5px; margin-bottom: 14px; }\n  .field:last-child { margin-bottom: 0; }\n  .lbl { font-family: var(--font-ui); font-size: .78rem; font-weight: 600; color: var(--rr-ink); }\n  .d-input { font-family: var(--font-ui); font-size: .9rem; padding: 10px 12px; border: 1.5px solid var(--rr-mist); border-radius: 6px; width: 100%; box-sizing: border-box; background: #fff; color: var(--rr-ink); }\n  .d-input:focus { border-color: hsl(var(--ring)); box-shadow: var(--shadow-ring); outline: none; }\n  .d-textarea { font-family: var(--font-ui); font-size: .9rem; padding: 10px 12px; border: 1.5px solid var(--rr-mist); border-radius: 6px; width: 100%; box-sizing: border-box; min-height: 80px; resize: vertical; background: #fff; color: var(--rr-ink); }\n  .d-textarea:focus { border-color: hsl(var(--ring)); box-shadow: var(--shadow-ring); outline: none; }\n  .field-row { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; }\n\n  /* Toast */\n  .toast-stack { position: fixed; bottom: 24px; right: 24px; display: flex; flex-direction: column; gap: 10px; width: 360px; z-index: 60; }\n  .toast { background: #fff; border: 1px solid var(--rr-parchment); border-radius: 6px; padding: 12px 14px; box-shadow: var(--shadow-md); display: grid; grid-template-columns: 22px 1fr auto; gap: 12px; align-items: center; }\n  .toast.success { border-color: #BBE0CC; }\n  .toast .toast-ico { color: var(--rr-slate-dark); }\n  .toast.success .toast-ico { color: var(--rr-success); }\n  .toast .toast-body { font-family: var(--font-ui); font-size: .85rem; color: var(--rr-ink); line-height: 1.4; }\n  .toast .toast-detail { display: block; font-family: var(--font-mono); font-size: .68rem; color: var(--rr-slate-dark); margin-top: 2px; }\n  .toast .toast-x { background: none; border: none; cursor: pointer; padding: 4px; color: var(--rr-slate-dark); }\n\n  /* Command palette */\n  .cmd-overlay { position: fixed; inset: 0; background: rgba(10,25,47,0.4); z-index: 70; display: flex; align-items: flex-start; justify-content: center; padding-top: 80px; }\n  .cmd-palette { width: min(640px,100%); background: #fff; border: 1px solid var(--rr-parchment); border-radius: 8px; box-shadow: var(--shadow-xl); overflow: hidden; }\n  .cmd-input-wrap { display: flex; align-items: center; gap: 10px; padding: 14px 18px; border-bottom: 1px solid var(--rr-parchment); }\n  .cmd-input-wrap input { flex: 1; border: none; outline: none; font-family: var(--font-ui); font-size: 1rem; color: var(--rr-ink); background: transparent; }\n  .cmd-input-wrap input::placeholder { color: var(--rr-slate); }\n  .cmd-group { padding: 8px 0; border-bottom: 1px solid var(--rr-parchment); }\n  .cmd-group:last-child { border-bottom: none; }\n  .cmd-heading { padding: 4px 18px; font-family: var(--font-ui); font-size: .65rem; font-weight: 700; letter-spacing: .12em; text-transform: uppercase; color: var(--rr-slate); }\n  .cmd-item { display: grid; grid-template-columns: 28px 1fr auto; gap: 12px; align-items: center; padding: 7px 18px; cursor: pointer; font-family: var(--font-ui); }\n  .cmd-item:hover { background: var(--rr-steel-050); }\n  .cmd-item .cmd-ico { color: var(--rr-slate-dark); }\n  .cmd-item:hover .cmd-ico { color: hsl(var(--primary)); }\n  .cmd-item .cmd-name { font-size: .88rem; color: var(--rr-ink); }\n  .cmd-item .cmd-sub { font-family: var(--font-mono); font-size: .7rem; color: var(--rr-slate-dark); }\n  .cmd-footer { padding: 8px 14px; border-top: 1px solid var(--rr-parchment); display: flex; justify-content: flex-end; gap: 12px; font-family: var(--font-ui); font-size: .7rem; color: var(--rr-slate-dark); }\n  .cmd-ava { width: 24px; height: 24px; border-radius: 999px; background: hsl(var(--primary)); color: #fff; display: inline-flex; align-items: center; justify-content: center; font-weight: 600; font-size: .62rem; }\n\n  /* Dropdown */\n  .dd-overlay { position: fixed; inset: 0; z-index: 55; }\n  .dd-menu { position: fixed; z-index: 56; background: #fff; border: 1px solid var(--rr-parchment); border-radius: 6px; padding: 6px; box-shadow: var(--shadow-md); min-width: 240px; }\n  .dd-head { padding: 6px 10px; }\n  .dd-name { font-family: var(--font-ui); font-weight: 600; font-size: .85rem; color: var(--rr-ink); }\n  .dd-sub { font-family: var(--font-mono); font-size: .7rem; color: var(--rr-slate-dark); }\n  .dd-sep { height: 1px; background: var(--rr-parchment); margin: 4px 0; }\n  .dd-item { display: flex; align-items: center; gap: 10px; padding: 7px 10px; border-radius: 4px; cursor: pointer; font-family: var(--font-ui); font-size: .85rem; color: var(--rr-ink); }\n  .dd-item:hover { background: var(--rr-steel-050); }\n  .dd-item .dd-ico { width: 16px; height: 16px; color: var(--rr-slate-dark); }\n  .dd-item:hover .dd-ico { color: hsl(var(--primary)); }\n\n  /* Notification items */\n  .notif-item { display: flex; gap: 10px; padding: 10px; border-radius: 4px; cursor: pointer; font-family: var(--font-ui); }\n  .notif-item:hover { background: var(--rr-steel-050); }\n  .notif-dot { width: 8px; height: 8px; border-radius: 999px; background: hsl(var(--primary)); flex-shrink: 0; margin-top: 6px; }\n  .notif-dot.read { background: var(--rr-mist); }\n  .notif-text { font-size: .82rem; color: var(--rr-ink); line-height: 1.4; }\n  .notif-time { font-family: var(--font-mono); font-size: .66rem; color: var(--rr-slate-dark); margin-top: 2px; }\n\n  /* Detail drawer rows */\n  .detail-row { display: grid; grid-template-columns: 120px 1fr; gap: 14px; padding: 10px 0; border-bottom: 1px solid var(--rr-parchment); }\n  .detail-row:last-child { border-bottom: none; }\n  .detail-k { font-family: var(--font-ui); font-size: .72rem; font-weight: 600; color: var(--rr-slate-dark); letter-spacing: .04em; text-transform: uppercase; padding-top: 2px; }\n  .detail-v { font-family: var(--font-ui); font-size: .9rem; color: var(--rr-ink); }\n\n  /* Clickable invoice rows */\n  .recent-table tbody tr { cursor: pointer; transition: background 200ms ease; }\n  .recent-table tbody tr:hover { background: var(--rr-steel-050); }\n</style>\n</head>\n<body>\n<div id=\"root\"></div>\n\n<script type=\"text/babel\" src=\"Sidebar.jsx\"></script>\n<script type=\"text/babel\" src=\"TopBar.jsx\"></script>\n<script type=\"text/babel\" src=\"KpiTile.jsx\"></script>\n<script type=\"text/babel\" src=\"PatientCard.jsx\"></script>\n<script type=\"text/babel\" src=\"AppointmentCard.jsx\"></script>\n<script type=\"text/babel\" src=\"LabPipeline.jsx\"></script>\n<script type=\"text/babel\" src=\"ToothChartTile.jsx\"></script>\n\n<script src=\"../../data/patients.js\"></script>\n<script src=\"../../data/appointments.js\"></script>\n<script src=\"../../data/invoices.js\"></script>\n\n<script type=\"text/babel\">\nconst NAV_MAP = { dashboard:'dashboard.html', patients:'patients.html', schedule:'schedule.html', plans:'treatment.html', lab:'lab.html', billing:'billing.html', comms:'communications.html', reports:'crm.html', settings:'dashboard.html' };\n\nconst NOTIFICATIONS = [\n  { id: 1, text: 'Alice Stevens confirmed her 08:30 appointment.', time: '2 min ago', read: false },\n  { id: 2, text: 'Lab case LC-2026-0469 returned from Pinnacle Dental Lab.', time: '18 min ago', read: false },\n  { id: 3, text: 'Recall reminder sent to Marcus Doan.', time: '1 hr ago', read: true },\n  { id: 4, text: 'Invoice INV-2026-0870 partial payment received.', time: '3 hr ago', read: true },\n];\n\nconst NewAppointmentDrawer = ({ onClose, onBook }) => {\n  const [patient, setPatient] = React.useState(window.PATIENTS[0].id);\n  const [date, setDate] = React.useState('2026-05-04');\n  const [time, setTime] = React.useState('09:00');\n\n  React.useEffect(() => {\n    const h = e => e.key === 'Escape' && onClose();\n    document.addEventListener('keydown', h);\n    return () => document.removeEventListener('keydown', h);\n  }, [onClose]);\n\n  const handleBook = () => {\n    const p = window.PATIENTS.find(x => x.id === patient);\n    onBook(p.first + ' ' + p.last + ' \\u00b7 ' + date + ' \\u00b7 ' + time);\n  };\n\n  return (\n    <>\n      <div className=\"drawer-overlay\" onClick={onClose} />\n      <aside className=\"drawer\" role=\"dialog\">\n        <div className=\"drawer-header\">\n          <div>\n            <div className=\"drawer-meta\">New appointment</div>\n            <div className=\"drawer-title\">Book a new appointment</div>\n            <div className=\"drawer-sub\">Select patient, provider, and slot.</div>\n          </div>\n          <button className=\"drawer-x\" onClick={onClose}>&times;</button>\n        </div>\n        <div className=\"drawer-body\">\n          <div className=\"field\">\n            <label className=\"lbl\">Patient</label>\n            <select className=\"d-input\" value={patient} onChange={e => setPatient(e.target.value)}>\n              {window.PATIENTS.map(p => <option key={p.id} value={p.id}>{p.first} {p.last} &middot; {p.id}</option>)}\n            </select>\n          </div>\n          <div className=\"field\">\n            <label className=\"lbl\">Provider</label>\n            <select className=\"d-input\" defaultValue=\"hau\">\n              <option value=\"hau\">Dr Hau Le &middot; Operatory 1</option>\n              <option value=\"sara\">Dr Sara Lim &middot; Operatory 2</option>\n              <option value=\"renu\">Hyg. Renu &middot; Operatory 3</option>\n            </select>\n          </div>\n          <div className=\"field\">\n            <label className=\"lbl\">Procedure</label>\n            <select className=\"d-input\" defaultValue=\"recall\">\n              <option value=\"recall\">Recall &middot; 6mo (30 min)</option>\n              <option value=\"crown-prep\">Crown prep (60 min)</option>\n              <option value=\"hygiene\">Hygiene &middot; scaling (30 min)</option>\n              <option value=\"implant\">Implant follow-up (90 min)</option>\n              <option value=\"composite\">Composite &middot; MOD (60 min)</option>\n              <option value=\"consult\">New patient consult (30 min)</option>\n              <option value=\"reline\">Denture relines (45 min)</option>\n              <option value=\"crown-seat\">Crown seat (45 min)</option>\n            </select>\n          </div>\n          <div className=\"field-row\">\n            <div className=\"field\">\n              <label className=\"lbl\">Date</label>\n              <input type=\"date\" className=\"d-input\" value={date} onChange={e => setDate(e.target.value)} />\n            </div>\n            <div className=\"field\">\n              <label className=\"lbl\">Time</label>\n              <input type=\"time\" className=\"d-input\" value={time} onChange={e => setTime(e.target.value)} />\n            </div>\n          </div>\n          <div className=\"field\">\n            <label className=\"lbl\">Duration</label>\n            <select className=\"d-input\" defaultValue=\"60\">\n              <option value=\"30\">30 min</option>\n              <option value=\"45\">45 min</option>\n              <option value=\"60\">60 min</option>\n              <option value=\"90\">90 min</option>\n            </select>\n          </div>\n          <div className=\"field\">\n            <label className=\"lbl\">Notes</label>\n            <textarea className=\"d-textarea\" placeholder=\"Reason for visit, special instructions...\" />\n          </div>\n        </div>\n        <div className=\"drawer-footer\">\n          <button className=\"btn btn-ghost btn-md\" onClick={onClose}>Cancel</button>\n          <button className=\"btn btn-primary btn-md\" onClick={handleBook}>Book appointment</button>\n        </div>\n      </aside>\n    </>\n  );\n};\n\nconst CommandPalette = ({ onClose, onNewAppt }) => {\n  const [q, setQ] = React.useState('');\n  React.useEffect(() => {\n    const h = e => e.key === 'Escape' && onClose();\n    document.addEventListener('keydown', h);\n    return () => document.removeEventListener('keydown', h);\n  }, [onClose]);\n  const pts = window.PATIENTS.filter(p => !q || (p.first + ' ' + p.last).toLowerCase().includes(q.toLowerCase()));\n  return (\n    <div className=\"cmd-overlay\" onClick={onClose}>\n      <div className=\"cmd-palette\" onClick={e => e.stopPropagation()}>\n        <div className=\"cmd-input-wrap\">\n          <svg width=\"18\" height=\"18\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"1.5\"><circle cx=\"11\" cy=\"11\" r=\"8\"/><line x1=\"21\" y1=\"21\" x2=\"16.65\" y2=\"16.65\"/></svg>\n          <input value={q} onChange={e => setQ(e.target.value)} placeholder=\"Search patients, invoices, appointments...\" autoFocus />\n          <span style={{ fontFamily: 'var(--font-mono)', fontSize: '.68rem', color: 'var(--rr-slate-dark)', padding: '2px 6px', background: 'var(--rr-off-white)', border: '1px solid var(--rr-parchment)', borderRadius: 3 }}>⌘K</span>\n        </div>\n        <div className=\"cmd-group\">\n          <div className=\"cmd-heading\">Patients</div>\n          {pts.slice(0, 4).map(p => (\n            <div key={p.id} className=\"cmd-item\" onClick={onClose}>\n              <span className=\"cmd-ava\">{(p.first[0] + p.last[0]).toUpperCase()}</span>\n              <div className=\"cmd-name\">{p.first} {p.last}</div>\n              <span className=\"cmd-sub\">{p.id}</span>\n            </div>\n          ))}\n        </div>\n        <div className=\"cmd-group\">\n          <div className=\"cmd-heading\">Quick actions</div>\n          <div className=\"cmd-item\" onClick={() => { onClose(); onNewAppt(); }}>\n            <svg className=\"cmd-ico\" width=\"16\" height=\"16\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"1.5\"><path d=\"M5 12h14\"/><path d=\"M12 5v14\"/></svg>\n            <div className=\"cmd-name\">New appointment</div>\n            <span className=\"cmd-sub\">⌘⇧A</span>\n          </div>\n        </div>\n        <div className=\"cmd-footer\"><span>↑↓ navigate</span><span>↵ open</span><span>esc close</span></div>\n      </div>\n    </div>\n  );\n};\n\nconst NotificationsDropdown = ({ onClose }) => (\n  <>\n    <div className=\"dd-overlay\" onClick={onClose} />\n    <div className=\"dd-menu\" style={{ top: 58, right: 80, minWidth: 340 }}>\n      <div className=\"dd-head\"><div className=\"dd-name\">Notifications</div><div className=\"dd-sub\">{NOTIFICATIONS.filter(n => !n.read).length} unread</div></div>\n      <div className=\"dd-sep\" />\n      {NOTIFICATIONS.map(n => (\n        <div key={n.id} className=\"notif-item\" onClick={onClose}>\n          <span className={'notif-dot' + (n.read ? ' read' : '')} />\n          <div><div className=\"notif-text\">{n.text}</div><div className=\"notif-time\">{n.time}</div></div>\n        </div>\n      ))}\n    </div>\n  </>\n);\n\nconst ProfileDropdown = ({ onClose }) => (\n  <>\n    <div className=\"dd-overlay\" onClick={onClose} />\n    <div className=\"dd-menu\" style={{ top: 58, right: 28 }}>\n      <div className=\"dd-head\"><div className=\"dd-name\">Dr Hau Le</div><div className=\"dd-sub\">hau@oakdentalcalgary.com</div></div>\n      <div className=\"dd-sep\" />\n      <div className=\"dd-item\" onClick={onClose}><svg className=\"dd-ico\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"1.5\"><path d=\"M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2\"/><circle cx=\"12\" cy=\"7\" r=\"4\"/></svg>Profile</div>\n      <div className=\"dd-item\" onClick={() => { window.location = 'dashboard.html'; }}><svg className=\"dd-ico\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"1.5\"><circle cx=\"12\" cy=\"12\" r=\"3\"/><path d=\"M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 1 1-2.83 2.83l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 1 1-4 0v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 1 1-2.83-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 1 1 0-4h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 1 1 2.83-2.83l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 1 1 4 0v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 1 1 2.83 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9c.26.604.852.997 1.51 1H21a2 2 0 1 1 0 4h-.09c-.658.003-1.25.396-1.51 1z\"/></svg>Settings</div>\n      <div className=\"dd-sep\" />\n      <div className=\"dd-item\" onClick={() => { window.location = 'login.html'; }}><svg className=\"dd-ico\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" strokeWidth=\"1.5\"><path d=\"M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4\"/><polyline points=\"16 17 21 12 16 7\"/><line x1=\"21\" y1=\"12\" x2=\"9\" y2=\"12\"/></svg>Sign out</div>\n    </div>\n  </>\n);\n\nconst DetailDrawer = ({ meta, title, sub, rows, onClose, actions }) => {\n  React.useEffect(() => {\n    const h = e => e.key === 'Escape' && onClose();\n    document.addEventListener('keydown', h);\n    return () => document.removeEventListener('keydown', h);\n  }, [onClose]);\n  return (\n    <>\n      <div className=\"drawer-overlay\" onClick={onClose} />\n      <aside className=\"drawer\" role=\"dialog\">\n        <div className=\"drawer-header\">\n          <div>\n            <div className=\"drawer-meta\">{meta}</div>\n            <div className=\"drawer-title\">{title}</div>\n            <div className=\"drawer-sub\" style={{ fontFamily: 'var(--font-mono)' }}>{sub}</div>\n          </div>\n          <button className=\"drawer-x\" onClick={onClose}>&times;</button>\n        </div>\n        <div className=\"drawer-body\">\n          {rows.map((r, i) => <div key={i} className=\"detail-row\"><span className=\"detail-k\">{r.k}</span><span className=\"detail-v\">{r.v}</span></div>)}\n        </div>\n        <div className=\"drawer-footer\">\n          <button className=\"btn btn-ghost btn-md\" onClick={onClose}>Close</button>\n          {actions}\n        </div>\n      </aside>\n    </>\n  );\n};\n\nconst Dashboard = () => {\n  const [drawerOpen, setDrawerOpen] = React.useState(false);\n  const [toasts, setToasts] = React.useState([]);\n  const [cmdOpen, setCmdOpen] = React.useState(false);\n  const [notifOpen, setNotifOpen] = React.useState(false);\n  const [profileOpen, setProfileOpen] = React.useState(false);\n  const [detail, setDetail] = React.useState(null);\n\n  const addToast = (msg, detail) => {\n    const id = Date.now();\n    setToasts(t => [...t, { id, msg, detail }]);\n    setTimeout(() => setToasts(t => t.filter(x => x.id !== id)), 4000);\n  };\n  const dismissToast = (id) => setToasts(t => t.filter(x => x.id !== id));\n  const navigate = (id) => { if (NAV_MAP[id]) window.location = NAV_MAP[id]; };\n\n  React.useEffect(() => {\n    const h = e => { if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); setCmdOpen(true); } };\n    document.addEventListener('keydown', h);\n    return () => document.removeEventListener('keydown', h);\n  }, []);\n\n  return (\n    <>\n    <div className=\"shell\">\n      <Sidebar active=\"dashboard\" onNav={navigate} />\n      <div className=\"stage\">\n        <TopBar clinicName=\"Oak Dental · Calgary\" breadcrumb={['Dashboard', 'Today']} onSearch={() => setCmdOpen(true)} onNotifications={() => setNotifOpen(o => !o)} onProfile={() => setProfileOpen(o => !o)} />\n        <div className=\"body\">\n          <div className=\"page-header\">\n            <div>\n              <h1 className=\"page-title\">Today's clinic</h1>\n              <div className=\"page-sub\">Saturday · May 4 · 2026 — 8 appointments scheduled · 5 lab cases in flight.</div>\n            </div>\n            <div style={{ display: 'flex', gap: 10 }}>\n              <button className=\"btn btn-ghost btn-md\" onClick={() => addToast('Day exported.', 'dashboard-2026-05-04.pdf')}>Export day</button>\n              <button className=\"btn btn-primary btn-md