-label=\"Close\"\n          >\n            ✕\n          </button>\n        </div>\n        <div className=\"flex-1 overflow-y-auto px-4 py-4\">{children}</div>\n        {footer && (\n          <div className=\"border-t border-zinc-200 px-4 py-3\">{footer}</div>\n        )}\n      </div>\n    </div>\n  );\n}"
