.center-modal { background: #fff; border-radius: 6px; box-shadow: var(--shadow-xl); width: min(820px, 92vw); max-height: 88vh; display: flex; flex-direction: column; animation: wsEnter 400ms cubic-bezier(0.16, 1, 0.3, 1); }
.center-modal-topbar { padding: 14px 28px; border-bottom: 1px solid var(--rr-parchment); display: flex; align-items: center; background: #fff; border-radius: 6px 6px 0 0; }
.center-modal-topbar .back-label { font-family: var(--font-ui); font-size: .85rem; color: var(--rr-slate-dark); }
.center-modal-body { flex: 1; overflow-y: auto; padding: 28px 32px; display: flex; flex-direction: column; gap: 24px; }

/* Hero card */
.appt-ws-hero { background: #fff; border: 1px solid var(--rr-parchment); border-radius: 6px; padding: 22px 24px; display: grid; grid-template-columns: 48px 1fr auto; gap: 18px; align-items: center; box-shadow: var(--shadow-xs); }
.appt-ws-ava { width: 48px; height: 48px; border-radius: 999px; background: hsl(var(--primary)); color: #fff; display: flex; align-items: center; justify-content: center; font-weight: 700; font-size: 1rem; flex-shrink: 0; }
.appt-ws-info { display: flex; flex-direction: column; gap: 3px; }
.appt-ws-name { font-family: var(--font-display); font-weight: 700; font-size: 1.2rem; color: var(--rr-navy-800); }
.appt-ws-detail { font-family: var(--font-ui); font-size: .82rem; color: var(--rr-slate-dark); }
.appt-ws-id { font-family: var(--font-mono); font-size: .72rem; color: var(--rr-slate-dark); }

/* Detail rows */
.detail-row { display: grid; grid-template-columns: 120px 1fr; gap: 14px; padding: 10px 0; border-bottom: 1px solid var(--rr-parchment); }
.detail-row:last-child { border-bottom: none; }
.detail-k { font-family: var(--font-ui); font-size: .72rem; font-weight: 600; color: var(--rr-slate-dark); letter-spacing: .04em; text-transform: uppercase; padding-top: 2px; }
.detail-v { font-family: var(--font-ui); font-size: .9rem; color: var(--rr-ink); }

/* Tabs */
.tab-bar { display: flex; gap: 0; border-bottom: 1px solid var(--rr-parchment); margin-bottom: 18px; }
.tab-btn { background: none; border: none; border-bottom: 2px solid transparent; padding: 10px 18px; font-family: var(--font-ui); font-size: .82rem; font-weight: 500; color: var(--rr-slate-dark); cursor: pointer; transition: color 200ms ease, border-color 200ms ease; }
.tab-btn:hover { color: var(--rr-ink); }
.tab-btn.active { color: hsl(var(--primary)); border-bottom-color: hsl(var(--primary)); font-weight: 600; }

/* Toast */
.toast-stack { position: fixed; bottom: 24px; right: 24px; display: flex; flex-direction: column; gap: 10px; width: 360px; z-index: 60; }
.toast { background: #fff; border: 1px solid var(--rr-parchment); border-radius: 6px; padding: 12px 14px; box-shadow: var(--shadow-md); display: grid; grid-template-columns: 22px 1fr auto; gap: 12px; align-items: center; }
.toast.success { border-color: #BBE0CC; }
.toast .toast-ico { color: var(--rr-slate-dark); }
.toast.success .toast-ico { color: var(--rr-success); }
.toast .toast-body { font-family: var(--font-ui); font-size: .85rem; color: var(--rr-ink); line-height: 1.4; }
.toast .toast-detail { display: block; font-family: var(--font-mono); font-size: .68rem; color: var(--rr-slate-dark); margin-top: 2px; }
.toast .toast-x { background: none; border: none; cursor: pointer; padding: 4px; color: var(--rr-slate-dark); }

